"""AssignmentObserver — the Observer seam: react to match outcomes without the
matcher knowing who's listening.

🎙️ "When a match happens the service announces it. Notifying the partner, audit
    logging, pushing to live tracking — all subscribers, none baked into matching."
"""
from __future__ import annotations

from abc import ABC, abstractmethod

from models import Assignment, Order


class AssignmentObserver(ABC):
    @abstractmethod
    def on_assigned(self, order: Order, assignment: Assignment) -> None: ...

    @abstractmethod
    def on_no_partner(self, order: Order) -> None: ...


class PartnerNotifier(AssignmentObserver):
    """Would push a notification to the partner's app. Here it records events."""

    def __init__(self) -> None:
        self.sent: list[str] = []

    def on_assigned(self, order: Order, assignment: Assignment) -> None:
        msg = f"notify partner {assignment.partner_id}: new order {order.id}"
        self.sent.append(msg)

    def on_no_partner(self, order: Order) -> None:
        # WHY: even the failure path is observable, so a retry/queue layer can hook in.
        self.sent.append(f"no partner for order {order.id}")


class OrderAuditLog(AssignmentObserver):
    """Append-only audit trail — proves Observer supports many listeners."""

    def __init__(self) -> None:
        self.events: list[tuple[str, str]] = []

    def on_assigned(self, order: Order, assignment: Assignment) -> None:
        self.events.append(("ASSIGNED", f"{order.id}->{assignment.partner_id}"))

    def on_no_partner(self, order: Order) -> None:
        self.events.append(("NO_PARTNER", order.id))
